#include <bits/stdc++.h>
using namespace std;

const int N=1e6+10;

int n,val[N],sz[N],ls[N],rs[N],d[N],a[N],cnt,ans,pl[N];

void dfs(int x){
    if(~ls[x])
        dfs(ls[x]),sz[x]+=sz[ls[x]]+1;
    int p=++cnt;
    if(~rs[x])
        dfs(rs[x]),sz[x]+=sz[rs[x]]+1;
    a[p]=sz[x]+val[x]*n,pl[p]=x;
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&val[i]);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&ls[i],&rs[i]);
    dfs(1);
    int l=0,r=0;
    sz[0]=-1;
    for(int i=1;i<=n;i++){
    	//printf("%d %d %d\n",pl[i],sz[i],val[i]);
        if(i<=r)
            d[i]=min(d[l+r-i],r-i);
        while(i-d[i]-1>0 && i+d[i]+1<=n && a[i-d[i]-1]==a[i+d[i]+1])
            d[i]++;
        if(i+d[i]>r)
            l=i-d[i],r=i+d[i];
        if(d[i]==sz[max(0,ls[pl[i]])]+1 && d[i]==sz[max(0,rs[pl[i]])]+1)
            ans=max(ans,sz[pl[i]]+1);
    }
    printf("%d",ans);
    return 0;
}
